python -c "
import tiktoken, string
enc = tiktoken.get_encoding('gpt2')

def lower(t):
    return t.lower()

def remove_punct(t):
    return t.translate(str.maketrans('', '', string.punctuation))

print(enc.encode('Hello World', transformers=lower))
print(enc.encode('HELLO', transformers=lower) == enc.encode('hello'))
print(enc.encode('Hello, World!', transformers=[lower, remove_punct]))
print(enc.encode('Hello, World!', transformers=[lower, remove_punct]) == enc.encode('hello world'))
print(enc.encode('hello world'))
"

